import { LitElement, css, html, customElement, state, property } from '@umbraco-cms/backoffice/external/lit';
import { tagManagerRepository, type CmsTag } from '../api/index.js';

@customElement('tag-workspace')
export class TagWorkspaceElement extends LitElement {
	@property({ type: Number })
	tagId?: number;

	@state()
	private _tag: CmsTag | null = null;

	@state()
	private _loading = true;

	async connectedCallback() {
		super.connectedCallback();
		if (this.tagId) {
			await this._loadTag();
		}
	}

	private async _loadTag() {
		if (!this.tagId) return;
		
		this._loading = true;
		this._tag = await tagManagerRepository.getTagById(this.tagId);
		this._loading = false;
	}

	render() {
		if (this._loading) {
			return html`<uui-loader></uui-loader>`;
		}

		if (!this._tag) {
			return html`<p>Tag not found</p>`;
		}

		return html`
			<umb-workspace-editor alias="TagManager.TagWorkspace">
				<div id="header" slot="header">
					<uui-button
						label="Back"
						look="secondary"
						@click=${() => history.back()}>
						<uui-icon name="icon-arrow-left"></uui-icon>
					</uui-button>
					<h2>${this._tag.tag}</h2>
				</div>
			</umb-workspace-editor>
		`;
	}

	static styles = css`
		:host {
			display: block;
			width: 100%;
			height: 100%;
		}

		#header {
			display: flex;
			align-items: center;
			gap: var(--uui-size-space-4);
		}
	`;
}

declare global {
	interface HTMLElementTagNameMap {
		'tag-workspace': TagWorkspaceElement;
	}
}

